/**
 * @param {number[]} digitSum
 * @return {number}
 */
function solve(digitSum) {
    const MOD = 1000000007;
    const V_MAX = 5000;

    /**
     * Calculates the sum of digits of a non-negative integer.
     * @param {number} n
     * @returns {number}
     */
    function getDigitSum(n) {
        let sum = 0;
        let s = Math.floor(Math.abs(n));
        while (s > 0) {
            sum += s % 10;
            s = Math.floor(s / 10);
        }
        return sum;
    }

    const N = digitSum.length;

    // DP[v]: Stores the count of valid arrays ending with value v at the current step i.
    // Initialize DP array of size V_MAX + 1 with zeros.
    let dp = new Array(V_MAX + 1).fill(0);

    // --- Base Case: i = 0 ---
    const S0 = digitSum[0];
    for (let v = 0; v <= V_MAX; v++) {
        if (getDigitSum(v) === S0) {
            dp[v] = 1;
        }
    }

    // --- Transitions: i = 1 to N-1 ---
    for (let i = 1; i < N; i++) {
        const Si = digitSum[i];
        let newDp = new Array(V_MAX + 1).fill(0);

        // 1. Calculate Prefix Sum P based on the current DP state (dp = DP[i-1])
        // P[k] = sum(dp[v] for v=0 to k)
        let prefixSum = new Array(V_MAX + 1).fill(0);
        prefixSum[0] = dp[0];
        for (let k = 1; k <= V_MAX; k++) {
            prefixSum[k] = (prefixSum[k - 1] + dp[k]) % MOD;
        }

        // 2. Calculate NewDP (DP[i])
        for (let v_curr = 0; v_curr <= V_MAX; v_curr++) {
            if (getDigitSum(v_curr) === Si) {
                // If arr[i] = v_curr, arr[i-1] must be <= v_curr.
                // The number of ways to reach this is the sum of counts for all previous values <= v_curr.
                newDp[v_curr] = prefixSum[v_curr];
            }
        }

        // Update DP state for the next iteration
        dp = newDp;
    }

    // --- Final Result ---
    // Sum up all counts in the final DP array
    let totalCount = 0;
    for (let v = 0; v <= V_MAX; v++) {
        totalCount = (totalCount + dp[v]) % MOD;
    }

    return totalCount;
}

