    const MOD = 1000000007;
    const V_MAX = 5000;

    /**
     * Calculates the sum of digits of a non-negative integer.
     * @param {number} n
     * @returns {number}
     */
    function getDigitSum(n) {
        let sum = 0;
        let s = Math.floor(Math.abs(n));
        while (s > 0) {
            sum += s % 10;
            s = Math.floor(s / 10);
        }
        return sum;
    }

    const N = digitSum.length;

    // DP[v]: Stores the count of valid arrays ending with value v at the current step i.
    // Initialize DP array of size V_MAX + 1 with zeros.
    let dp = new Array(V_MAX + 1).fill(0);

    // --- Base Case: i = 0 ---
    const S0 = digitSum[0];
    for (let v = 0; v <= V_MAX; v++) {
        if (getDigitSum(v) === S0) {
            dp[v] = 1;
        }
    }

    // --- Transitions: i = 1 to N-1 ---
    for (let i = 1; i < N; i++) {
        const Si = digitSum[i];
        let newDp = new Array(V_MAX + 1).fill(0);

        // 1. Calculate Prefix Sum P based on the current DP state (dp = DP[i-1])
        // P[k] = sum(dp[v] for v=0 to k)
