                // The number of ways to reach this is the sum of counts for all previous values <= v_curr.
                newDp[v_curr] = prefixSum[v_curr];
            }
        }

        // Update DP state for the next iteration
        dp = newDp;
    }

    // --- Final Result ---
    // Sum up all counts in the final DP array
    let totalCount = 0;
    for (let v = 0; v <= V_MAX; v++) {
        totalCount = (totalCount + dp[v]) % MOD;
    }

